/*!50503 SET NAMES utf8mb4 */;

/* 2026-01-20 liuyan 新增本体ontology开头的表建表语句，防止部分现场不能自动建表 */

DROP TABLE IF EXISTS `ontology_action_process`;

CREATE TABLE `ontology_action_process` (
  `id` varchar(64) COLLATE utf8mb4_general_ci NOT NULL COMMENT '主键ID',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `action_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '动作NAME',
  `api_param` varchar(4000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行参数',
  `api_path` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行地址',
  `create_user` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `end_time` datetime DEFAULT NULL COMMENT '结束时间',
  `object_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '对象NAME',
  `ontology_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体NAME',
  `start_time` datetime DEFAULT NULL COMMENT '开始时间',
  `state` int DEFAULT NULL COMMENT '执行状态',
  `message` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行地址',
  `task_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `task_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '动作NAME',
  `task_type` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '程序类型',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_api` */

DROP TABLE IF EXISTS `ontology_api`;

CREATE TABLE `ontology_api` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT 'API唯一id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `api_desc` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'API描述',
  `api_method` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '请求方式: GET/POST/PUT等',
  `api_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'API名称',
  `api_timeout_ms` int DEFAULT NULL COMMENT 'API接口超时时间：单位毫秒',
  `create_user` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '创建用户',
  `update_user` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '修改用户',
  `url` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'API请求地址',
  `workspace_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '工作空间/团队名',
  `api_type` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '接口类型: object/logic/action',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_api_function` */

DROP TABLE IF EXISTS `ontology_api_function`;

CREATE TABLE `ontology_api_function` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '函数唯一ID',
  `function_label` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '函数标签',
  `function_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '函数名称',
  `function_params` longtext COLLATE utf8mb4_general_ci COMMENT '函数参数',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_api_param` */

DROP TABLE IF EXISTS `ontology_api_param`;

CREATE TABLE `ontology_api_param` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT 'API参数唯一ID',
  `api_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'API ID',
  `default_value` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `is_required` int DEFAULT NULL COMMENT '是否必填: 0 - 否，1 - 是',
  `param_desc` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '参数描述',
  `param_method` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '传入方式：path/query/body/header/cookie',
  `param_mode` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '类别：request/response',
  `param_name` varchar(128) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '参数名称',
  `param_type` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '参数类型：string/integer/number',
  `function_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'API函数ID',
  `is_builtins` int DEFAULT NULL COMMENT '是否内置: 0 - 否，1 - 是',
  `parent_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '父API参数ID',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_canvas_node` */

DROP TABLE IF EXISTS `ontology_canvas_node`;

CREATE TABLE `ontology_canvas_node` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点id',
  `canvas_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '画布id',
  `data_status` int DEFAULT NULL COMMENT '初始化数据状态，1-已初始化数据，0-未初始化',
  `element_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '节点所使用元素id：对象id/逻辑id/动作id',
  `node_type` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '节点类型:object-对象，logic-逻辑，action-动作',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_center_object_attribute` */

DROP TABLE IF EXISTS `ontology_center_object_attribute`;

CREATE TABLE `ontology_center_object_attribute` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '对象类型属性唯一id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `attribute_desc` varchar(2048) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `attribute_inst` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型英文名',
  `attribute_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型属性名',
  `field_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型字段名',
  `field_type` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型字段类型',
  `is_primary_key` int DEFAULT NULL COMMENT '状态，1为是，0为否',
  `is_title` int DEFAULT NULL COMMENT '状态，1为是，0为否',
  `object_type_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '对象类型id',
  `shared_attribute_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型属性名',
  `status` int DEFAULT NULL COMMENT '1启用/0禁用',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_center_object_type` */

DROP TABLE IF EXISTS `ontology_center_object_type`;

CREATE TABLE `ontology_center_object_type` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '对象类型唯一id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `center_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '共享中心id',
  `ds_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '数据源id',
  `ds_schema` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '数据源schema',
  `icon` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '图标',
  `object_type_desc` text COLLATE utf8mb4_general_ci COMMENT '本体对象类型描述',
  `object_type_label` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型中文名',
  `object_type_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型英文名',
  `ontology_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体管理器id',
  `owner_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拥有者标识',
  `status` int DEFAULT NULL COMMENT '状态，1为启用，0为禁用',
  `table_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '数据源表名',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_change_log` */

DROP TABLE IF EXISTS `ontology_change_log`;

CREATE TABLE `ontology_change_log` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '连接类型唯一id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `change_target_desc` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '变更对象描述',
  `change_target_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '变更对象标识',
  `change_target_type` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '变更对象类型',
  `change_type` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '变更类型',
  `ontology_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体管理器id',
  `owner_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拥有者标识',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_code_repo` */

DROP TABLE IF EXISTS `ontology_code_repo`;

CREATE TABLE `ontology_code_repo` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '仓库ID',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `ontology_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体ID',
  `owner_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拥有者',
  `repo_address` varchar(256) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仓库地址',
  `repo_name` varchar(256) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仓库名称',
  `repo_type` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仓库类型/语言：python - Python；rest - Rest API',
  `status` int DEFAULT NULL COMMENT '状态，1为启用，0为禁用',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_config` */

DROP TABLE IF EXISTS `ontology_config`;

CREATE TABLE `ontology_config` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '接口唯一id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `config_key` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '配置字段键值',
  `config_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '配置字段值',
  `description` text COLLATE utf8mb4_general_ci COMMENT '配置字段描述',
  `status` int DEFAULT NULL COMMENT '状态，1为启用，0为禁用',
  `config_type` text COLLATE utf8mb4_general_ci COMMENT '参数类型',
  `config_source` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '参数来源',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_config_group` */

DROP TABLE IF EXISTS `ontology_config_group`;

CREATE TABLE `ontology_config_group` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '主键',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `code` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分组编码',
  `name` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分组名称',
  `status` int DEFAULT NULL COMMENT '状态，1为启用，0为禁用',
  `group_type` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分组类型',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_data_change_log` */

DROP TABLE IF EXISTS `ontology_data_change_log`;

CREATE TABLE `ontology_data_change_log` (
  `id` bigint NOT NULL COMMENT '数据变更唯一id',
  `affected_rows` int DEFAULT NULL COMMENT '影响的行数',
  `change_details` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '变更详情JSON',
  `created_at` datetime DEFAULT NULL COMMENT '记录创建时间',
  `full_data` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '完整记录数据',
  `object_type_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '对象类型名称',
  `operation_type` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '操作类型',
  `record_count_after` int DEFAULT NULL COMMENT '操作后记录总数',
  `record_count_before` int DEFAULT NULL COMMENT '操作前记录总数',
  `track_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '跟踪id',
  `order` bigint DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_dify_graph` */

DROP TABLE IF EXISTS `ontology_dify_graph`;

CREATE TABLE `ontology_dify_graph` (
  `id` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT 'dify任务id',
  `conversation_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'dify会话id',
  `graph` longtext COLLATE utf8mb4_general_ci COMMENT '图谱信息',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_dify_task` */

DROP TABLE IF EXISTS `ontology_dify_task`;

CREATE TABLE `ontology_dify_task` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '主键id',
  `batch_idx` int DEFAULT NULL COMMENT '子任务编号',
  `batch_num` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '批次号',
  `case_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '批次号',
  `conversation_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '会话id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `exec_user` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行用户',
  `last_exec_detail` text COLLATE utf8mb4_general_ci COMMENT '对比分析信息',
  `last_exec_result` text COLLATE utf8mb4_general_ci COMMENT '执行结果',
  `last_exec_time` datetime DEFAULT NULL COMMENT '执行时间',
  `question` text COLLATE utf8mb4_general_ci COMMENT '用例问题',
  `status` int DEFAULT NULL COMMENT '执行状态',
  `summary` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '结果概要',
  `task_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '任务id',
  `type` int DEFAULT NULL COMMENT '状态，1为test，0为chat',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_init_data_task` */

DROP TABLE IF EXISTS `ontology_init_data_task`;

CREATE TABLE `ontology_init_data_task` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '主键ID',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `create_user` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '创建人',
  `ds_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '数据源名',
  `ds_schema` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '数据源schema',
  `job_code` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '同步数据任务编码',
  `object_type_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '对象类型ID',
  `object_type_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '对象类型名称',
  `scene_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仿真场景ID',
  `scene_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仿真场景名称',
  `table_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '表名',
  `task_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '初始化数据任务ID',
  `status` int DEFAULT NULL COMMENT '数据初始化任务状态: 0 - 新建，1 - 运行中，2 - 成功，3 - 失败，4 - 未绑定数据源',
  `message` longtext COLLATE utf8mb4_general_ci COMMENT '执行信息',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_interface` */

