  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `action_desc` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '动作描述',
  `action_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体对象类型动作名称',
  `action_type` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '动作类型：create - 创建对象，update - 修改对象，delete - 删除对象',
  `icon` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '图标',
  `object_type_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '对象类型id',
  `ontology_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体管理器id',
  `status` int DEFAULT NULL COMMENT '状态，1为启用，0为禁用',
  `action_label` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '动作类型中文名',
  `build_type` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '构建方式/逻辑类型：function - Function，api - API，link - Link',
  `file_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件名',
  `function_code` longtext COLLATE utf8mb4_general_ci COMMENT '函数代码',
  `intput_param` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '入参',
  `output_param` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '出參',
  `owner_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '发布人',
  `repo_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仓库名',
  `signature_detail` longtext COLLATE utf8mb4_general_ci,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

