CREATE TABLE `ontology_simu_scene` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '仿真场景id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `canvas_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '画布id',
  `description` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仿真场景描述',
  `ontology_id` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体管理器id',
  `owner_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '创建/修改用户',
  `scene_label` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仿真场景中文名称',
  `scene_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '仿真场景英文名称',
  `status` int DEFAULT NULL COMMENT '状态，1为启用，0为禁用',
  `workspace_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '工作空间/团队名',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_tag` */

DROP TABLE IF EXISTS `ontology_tag`;

CREATE TABLE `ontology_tag` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '标签唯一id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `tag_desc` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '描述',
  `tag_label` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标签中文名',
  `tag_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标签名',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_use_case` */

DROP TABLE IF EXISTS `ontology_use_case`;

CREATE TABLE `ontology_use_case` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '主键id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `expected_result` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '预期结果',
  `ontology_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体id',
  `ontology_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体名称',
  `owner_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '创建用户',
  `question` text COLLATE utf8mb4_general_ci COMMENT '用例问题',
  `system_prompt` longtext COLLATE utf8mb4_general_ci COMMENT '提示词',
  `workspace_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '工作空间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Table structure for table `ontology_version` */

DROP TABLE IF EXISTS `ontology_version`;

CREATE TABLE `ontology_version` (
  `id` varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '版本ID',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `last_update` datetime DEFAULT NULL COMMENT '修改时间',
  `oper_status` int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  `sync_status` int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  `latest` int DEFAULT NULL COMMENT '最新版本：0 - 最新版本，1 - 历史版本',
  `ontology_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体ID',
  `owner_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '发布人',
  `version_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '版本名称/版本号',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

