ption[0].fields;if (n) {n.forEach((fItem)=>{fItem.name = fItem.fieldName;fItem.label = fItem.fieldLabel;}); const nparse = self.props.evalField(self, n);self.formRef.current.setFieldsValue({ dataAware: nparse, stepVars: nparse, tabIdLabel: selOption[0].label, tabName: selOption[0].name });} else {self.props.getTabFields(self, value);}}}\"},\"visible\":{\"val\":\"configMode\",\"var\":\"advanced\"},\"dependVal\":[\"advanced\"]},{\"label\":\"数据源\",\"field\":\"dsName\",\"type\":\"input\",\"hidden\":true,\"options\":{\"defaultValue\":\"\"}},{\"type\":\"elxFieldTable\",\"isGrid\":false,\"field\":\"dataAware\",\"label\":\"数据识别\",\"initialValue\":[],\"options\":{\"addOper\":true,\"editAllOper\":false,\"deleteOper\":true,\"rowKey\":\"index\",\"sortable\":false,\"index\":true,\"border\":false,\"loading\":false,\"pagination\":true,\"onChange\":\"function(self,value,item,option){console.log(\'self\',self);}\",\"model\":{\"fields\":[{\"name\":\"name\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"字段\",\"type\":\"input\",\"options\":{}},{\"name\":\"mappingRule\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"选取方式\",\"type\":\"input\",\"options\":{}}]}}}],\"getTabFields\":\"function(self, selTabId) {axios.get(/api/select/logic/model/from/dataps, { params: { offset: 0, limit: 50, dsType: \'kafka\', exceptTabIds: selTabId, dataSrc: \'draft\' } }).then(function(response) { console.log(\'表名返回数据\', response); field.options.loading = false; var { data } = response.data; if (data.content && data.content.length > 0) { const tabInfo = data.content[0];let n = tabInfo.fields || [];n.forEach((fItem)=>{fItem.name = fItem.fieldName;fItem.label = fItem.fieldLabel;}); const nparse = self.props.evalField(self, n);self.formRef.current.setFieldsValue({ dataAware: nparse, stepVars: nparse, tabIdLabel: tabInfo.modelLabel, tabName: tabInfo.modelName }); }}).catch(function(err) { field.options.loading = false; });}\",\"setStepVars\":\"function(data){if(data.dataAware){data.stepVars = data.dataAware.concat(data.preStepVars || [])} else {data.stepVars = data.preStepVars || []}}\",\"beforeRender\":\"function(self,fields, teamName) {const {currentCell,...formOptions}=self.props;formOptions.getTabs(self,\'tabId\',\'\',\'\',\'edit\');}\",\"evalField\":\"function(self,tabData){console.log(\'evalField\', self, tabData);let tabDatax=tabData.slice();tabDatax.forEach(function(value){ const extendItems = JSON.parse(value.extendItems || \'{}\');value.mappingRule=extendItems.selectionType || \'\'});return tabDatax;};\",\"getTabs\":\"function(self,fieldName, dsName, query, type) {if (!self) { return; }let fields = self.props.fields.filter(function(item) { return item.field == fieldName; });if (fields.length == 1) { var field = fields[0];axios.get(/api/select/logic/model/from/dataps, { params: { offset: 0, limit: 50, keyWord: query, dsType: \'kafka\', dataSrc: \'draft\' } }).then(function(response) { console.log(\'表名返回数据\', response);field.options.loading = false; var { data } = response.data; if (data.content && data.content.length > 0) { var options_ = data.content.map(function(option) { let obj = { label: option.modelLabel, value: option.id, name: option.modelName, fields: option.fields, datasource: option.datasource }; return obj; }); const tabId=self.formRef.current.getFieldValue(\'tabId\');const tabIdLabel=self.formRef.current.getFieldValue(\'tabIdLabel\');if (tabId) {const selOption = options_.filter((sItem)=>{if(sItem.value === tabId) {return sItem;}});if(selOption.length === 0) {options_.push({value: tabId, label: tabIdLabel});}}field.options.options = JSON.parse(JSON.stringify(options_));self.setOptionsData(field, fieldName); }}).catch(function(err) { field.options.loading = false; });}}\",\"getOutputField\":\" (self,fieldName, dsName, tabName, type) => {if (!self) {return};console.log(\'dsName,tabName\', dsName, tabName,self.props);let fields=self.props.fields.filter((item) => {return item.field == fieldName;});if (fields.length == 1) {var fiel