insert into dataos_meta_proc_step_define (step_inst, children_type, domain, ext_conf, group_type, remark, step_cfg, step_icon, step_inst_label, step_seq, step_state, step_style, step_id, notify, run_engine) values('checkExistsTable','','develop','{\"allowCrtTab\":\"1\",\"regexp\":\"/n*/gi\",\"errorInfo\":\"\",\"notify\":\"\"}','TableOperation','“判断表是否存在”插件用于判断数据库中指定的表是否存在，配置参数的说明如下：\n数据源：表所属的数据库\n模式名：表示要判断表的数据库schema归属\n表名：需要判定的表名\n说明：如果表存在则成功返回走成功分支，如果表不存在则运行失败走失败分支。\n','{\"fields\":[{\"type\":\"input\",\"field\":\"stepLabel\",\"label\":\"节点名\",\"options\":{\"placeholder\":\"请输入节点名称\"},\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"required\":true,\"rules\":\"[{ validator:function(value,cb,ref) {console.log(ref);if (!value) {return cb(\'必须填写节点名称\');}return cb();} }]\"},{\"type\":\"elxDs\",\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"options\":{\"metaTableNameVisible\":false,\"param\":{\"inline\":false,\"stepLabelShow\":false,\"showSearch\":true,\"filterOption\":false,\"scenario\":1,\"dsCategory\":\"rdb,mpp,bigdata,analytic\",\"storageType\":\"storage\",\"publicOptionName\":\"all\",\"env\":\"union\",\"parentDsNameShow\":false,\"labelShow\":true,\"labelSuffix\":\":\",\"labelWidth\":\"150px\",\"visible\":true}}},{\"type\":\"input\",\"field\":\"tableName\",\"label\":\"表名\",\"options\":{\"placeholder\":\"请输入表名\"},\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16}}]}','icon-judge','判断表是否存在','2','1','image','2',NULL,NULL);
