turn obj;});field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field,fieldName);};}).catch(function(err) {console.log(err);});};};\",\"beforeRender\":\"function(self,fields,teamName){const {currentCell,...formOptions}=self.props;formOptions.getDsName(self,fields,\'dsName\',\'\',teamName);}\"}','icon-fileDelete','文件删除','4','1','image','20',NULL,'');
