ld.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field, fieldName);};const tabName=self.formRef.current.getFieldValue(\'tabName\');if (type == \'edit\' && tabName) {self.props.getOutputField(self, \'outputField\', dsName,schema, tabName, \'edit\');};} else {if (type == \'onSearch\') {selectInputData.setState({optionsNew: []});} else {field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field, fieldName);}}}).catch(function(err) {field.options.loading=false;});}}\",\"getOutputField\":\"(self,fieldName, dsName, schema, tabName, type) => {if (!self) {return};console.log(\'dsName,tabName\', dsName, tabName, self.props);let fields=self.props.fields.filter((item) => {return item.field == fieldName});if (fields.length == 1 && tabName) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTableFields, {params:{dsName,tabName,schema}}).then(function(response) {console.log(\'获取字段信息表名-的返回数据\', response);field.options.loading=false;var {data}=response.data;field.options.loading=false;console.log(\'test-field\', self.props.fields);if (data && data.length > 0) {let TableFields=field.options.model.fields;const fieldMappingMap=new Map();TableFields.filter(v => v.name == \'fieldMapping\')[0].options.options.forEach(v => fieldMappingMap.set(v.label.toUpperCase(), v.label));let outputFields=_.map(data, function(item, index) {let fieldMapping=fieldMappingMap.get(item.colname.toUpperCase());return {...item,\'label\': \'\',\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'name\': item.colname,\'fieldMapping\': fieldMapping,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'}});let options_=_.map(data, function(item, index) {return {...item,\'label\': item.colname,\'value\': item.colname,\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'}});let modelFields=TableFields.map(itm => {if (itm.name == \'name\') {let itm_={...itm,options: {...itm.options,options: options_}};return itm_}else {return itm}});field.options.model.fields=modelFields;self.setOptionsData(field, fieldName);if (type == \'add\') {self.formRef.current.setFieldsValue({outputField: outputFields})}} else {self.Message.error(${response.data.message});self.setOptionsData(field, fieldName);}}).catch(function(err) {console.log(err);field.options.loading=false;self.setOptionsData(field, fieldName);});}}\",\"getSql\":\"(setCodeFun,self,fields,field)=>{const from=self.formRef.current.getFieldsValue();let fieldList=from.outputField.map(item=>{let obj={name:item.name,label:item.label,type:item.dataType,};return obj;});let params={tabName:from.tabName||\'\',dsType:\'sqlserver\',fieldList: fieldList||[]};console.log(\'params\',from,params);axios.post(/_api/_/dataaccess/tab/sql,params).then((response)=> {console.log(\'getSql\',response);let {data}=response;if(data.code == \'200\'){setCodeFun(data.message);};}).catch(err=>{console.log(err);});}\",\"getSchemas\":\"function(self,fieldName,dsName,query,){if(!self){return;};let fields=self.props.fields.filter(function(item){return item.field==fieldName;});if(fields.length==1){var field=fields[0];const teamName=sessionStorage.getItem(\'teamName\');axios.get(/_api/_/modoAppTeamDs/ds/schema/${dsName}/${teamName}).then(function(response){console.log(\'modoAppTeamDs\',response);var {data} =response.data;const options=data.schemaList;if(options&&options.length>0){const schemaOptionObj={union:[],dev:[],prod:[]};options.map((option)=>{const schema=option.split(\'|\');if(schema.length>0){if(schema.length==1){schema.push(schema[0])};const devOption={label:schema[0],value:schema[0]};const prodOption={label:schema[1],value:schema[1]};let unionOption;if(schema[0]===schema[1]){unionOption={label:schema[0],value:schema[0]};}else{unionOption={label:开发：${schema[0]}生产：${schema[1]},value:${schema[0]}|${schema[1]}};}schemaOptionObj.union.push(unionOption);schemaOptionObj.dev.push(devOption);schemaOptionObj.prod.push(prodOption)}});field.options.options=JSON.parse(JSON.stringify(schemaOptionObj[\'union\']));self.setOptionsData(field,fieldName);}else{field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field,fieldName);};}).catch(function(err){});}}\",\"executeSql\":\"(setMessage,dsProfile,runSql,self,fields,field)=>{const from=self.formRef.current.getFieldsValue();let dsProfile_=[\'dev\'];const dsSchema=self.formRef.current.getFieldValue(\'dsSchema\');if(dsProfile){dsProfile_=[\'dev\',\'pro\'];}else{dsProfile_=[\'dev\'];};let params={dsName:from.dsName||\'\',dsProfile:dsProfile_,dsType: \'sqlserver\',windowId:\'windowId\',dsSchema:dsSchema,runSql:runSql||\'\'};axios.post(/_api/_/dataaccess/execute,params).then((response)=> {console.log(\'getSql\',response);let {data}=response;console.log(\'getSql--data\',data);if(data.success){setMessage({type:\'success\',msg:\'执行成功!\'});}else{setMessage({type:\'error\',msg:data.message});};}).catch(err=>{console.log(err);});}\"}','icon-mysqlRead','sqlserver写','3','1','image','21a60496e33a44b7a59a57eb15726d18',NULL,'seaTunnel');
insert into dataos_meta_proc_step_define (step_inst, children_type, domain, ext_conf, group_type, remark, step_cfg, step_icon, step_inst_label, step_seq, step_state, step_style, step_id, notify, run_engine) values('fileScan','','develop','{\"allowCrtTab\":\"1\",\"regexp\":\"/n*/gi\",\"errorInfo\":\"\",\"notify\":\"\"}','VFSFile','“文件扫描”插件主要用于在文件系统上进行文件扫描，发现文件。插件配置参数说如下：\n扫描几天之内：支持只扫描几天之内的文件，要求文件路径结构以日期进行分层，该项可不填。\n扫描目录：进行扫描的文件路径。根据表8.1.1来配置\n文件匹配正则：目标文件名的正则表达式，遵循正则表达式用法。“.*” 表示匹配所有文件。\n是否深度扫描：当目录有下一级子目录时是否进行扫描\n插件输出：扫描到的文件列表对象。${foundFiles}\n文件系统---语法---示例\n本地---File://filepath---file:///home/hadoop/test\nftp---ftp://userid:password@ip/filepath---ftp://db2inst1:db2inst1@10.5.1.25/home/db2inst1/test_20151023\nSftp---Sftp://userid:password@ip/filepath---sftp://db2inst1:db2inst1@10.5.1.25/test_20151023\nHdfs---hdfs://clusterName/filepath---hdfs://hbcm/interface\n注意：  当扫描的文件个数超过1000的时候，需要用replace函数来处理。目前暂不支持HDFS文件系统格式扫描。另外选择FTP的时候路径要写绝对路径,选择sftp的时候要填写相对路径,这里的相对路径是指：用户登录之后默认的目录，命令行模式下执行“cd ”命令回车，这是“pwd”所显示的目录信息不用填写在插件扫描目录中。一般默认路径为“/home/用户名”\n${foundFiles} 为插件的返回对象，该对象的相关属性如下：\n属性---属性说明\nvfsServer---文件服务器信息\nrelativePath---文件路径\nfileName---文件名称\nfileSize---文件大小\nlastModifiedTime---文件最后修改时间\nfoundTime---文件扫描到的时间\n','{\"fields\":[{\"type\":\"input\",\"field\":\"intervalday\",\"label\":\"扫描几天之内\",\"options\":{\"placeholder\":\"请输入扫描几天之内\"},\"initialValue\":\"\"},{\"type\":\"select\",\"field\":\"dsName\",\"label\":\"数据源\",\"options\":{\"placeholder\":\"请选择数据源\",\"options\":[],\"allowClear\":true},\"required\":false},{\"type\":\"input\",\"field\":\"sourceDirs\",\"label\":\"扫描目录\",\"options\":{\"placeholder\":\"请输入扫描目录\"},\"initialValue\":\"\",\"isRemark\":true,\"remark\":\"进行扫描的文件路径。<br/>文件系统---语法---示例 <br/>本地---File://filepath---file:///home/hadoop/test <br/>ftp---ftp://userid:password@ip/filepath---ftp://db2inst1:db2inst1@10.5.1.25/home/db2inst1/test_20151023 <br/>Sftp---Sftp://userid:password@ip/filepath---sftp://db2inst1:db2inst1@10.5.1.25/test_20151023 <br/>Hdfs---hdfs://clusterName/filepath---hdfs://hbcm/interface\"},{\"type\":\"input\",\"field\":\"fileNameFilter\",\"label\":\"文件匹配正则\",\"options\":{\"placeholder\":\"请输入文件匹配正则\"},\"initialValue\":\"\",\"isRemark\":true,\"remark\":\"文件匹配正则：目标文件名的正则表达式，遵循正则表达式用法。“.”匹配除换行之外的任何单个字符，“*”表示零次或多次匹配前面的字符或子表达式；${taskid}可匹配批次号。\"},{\"type\":\"radioGroup\",\"label\":\"是否深度扫描\",\"field\":\"depthwise\",\"initialValue\":\"false\",\"options\":{\"options\":[{\"label\":\"是\",\"value\":\"true\"},{\"label\":\"否\",\"value\":\"false\"}]},\"isRemark\":true,\"remark\":\"当目录有下一级子目录时是否进行扫描\"}],\"getDsName\":\"function(self,fields, fieldName, dsName, teamName) {var fieldDatas=_.filter(fields, function(item) {return item.field == fieldName;});if (fieldDatas.length == 1) {var field=fieldDatas[0];axios.get(/_api/_/workspace/ds-list, {params: {dsType: \'ftp,sftp\',dsCategory: \'\',workspaceId:self.props.apiInfo.workspaceId}}).then(function(response) {console.log(\'数据源返回数据\', response);let {data}=response;if (data.data) {let options_=data.data.map(function(itm) {let obj={label: itm.label,value: itm.name,...itm,};return obj;});field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field,fieldName);};}).catch(function(err) {console.log(err);});};};\",\"beforeRender\":\"function(self,fields,teamName){const {currentCell,...formOptions}=self.props;formOptions.getDsName(self,fields,\'dsName\',\'\',teamName);}\"}','icon-fileScan','文件扫描','5','1','image','22',NULL,'');
