ld == fieldName;});if (fields.length == 1 && tabName) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTableFields, {params:{dsName,tabName,schema,}}).then(function(response) {console.log(\'获取字段信息表名-的返回数据\', response);field.options.loading=false;var {data}=response.data;field.options.loading=false;if (data && data.length > 0) {console.log(\'outputFields\');let outputFields=_.map(data, function(item, index) {return {...item,\'label\': \'\',\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'name\': item.colname,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'};});let options_=_.map(data, function(item, index) {return {...item,\'label\': item.colname,\'value\': item.colname,\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'};});let TableFields=field.options.model.fields;let modelFields=TableFields.map(itm => {if (itm.name == \'name\') {let itm_={...itm,options: {...itm.options,options: options_}};return itm_;}else {return itm;}});field.options.model.fields=modelFields;self.setOptionsData(field, fieldName);if (type == \'add\') {self.formRef.current.setFieldsValue({outputField: outputFields});};}else{self.Message.error(${response.data.message});field.options.loading=false;self.setOptionsData(field, fieldName);};}).catch(function(err) {console.log(err);field.options.loading=false;self.setOptionsData(field, fieldName);});}}\",\"getPreviewData\":\"(setPreviewFun,setLoadingFun,setTableDataFun,self,fields,field)=> {if (!self) {return;};const dsName=self.formRef.current.getFieldValue(\'dsName\');const tabName=self.formRef.current.getFieldValue(\'tabName\');const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\').split(\'|\')[0];let params={dsName: dsName||\'\',table:tabName||\'\',fileType: \'gbase\',schema:schemaDev,dsConf:\'\',profile:\'dev\'};setLoadingFun(true);axios.post(/_api/_/data-integration/source/preview-data