Id = \'\';item.fieldExpression = \'\'; } return item;}); formDatas.insertRelFields = tabData; props_.formRef.setFieldsValue({ ...formDatas});}\"}},{\"name\":\"fieldExpression\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"字段表达式\",\"type\":\"SelectInput\",\"options\":{\"options\":[],\"defaultSelect\":true,\"defaultValue\":\"\",\"onChange\":\"function(props_, value, column, rowData, cellConfig) { console.log(\'-------change-mappingRule\', props_, value, column, rowData, cellConfig); if (value) { let formDatas = props_.formRef.getFieldsValue(); const relFieldsDatas = formDatas.insertRelFields || []; let currRowValue = { ...rowData }; if (currRowValue.mappingType == \'fieldMapping\') { var filterOptions = _.filter(column.options.options, function(option) { return option.name == value; }); if (filterOptions.length > 0) { currRowValue.relId = filterOptions[0].id; } } let tabData = relFieldsDatas.map((item) => { if (item.index === currRowValue.index) { item.relId = currRowValue.relId; item.fieldExpression = value; } return item; }); formDatas.insertRelFields = tabData; props_.formRef.setFieldsValue({ ...formDatas }); } }\"}}]},\"onChange\":\"function(data, formRef, formConfigs) { console.log(\'-------change-table\', data, formRef, formConfigs); } \"}}],\"getDsName\":\"function(self, fieldName, teamName) { if (!self) { return; } let fields = self.props.fields.filter(function(item) { return item.field == fieldName; }); if (fields.length == 1) { var field = fields[0]; axios.get(/_api/_/modoAppTeamDs/getTeamDsInfoList?, { params: { dsCategory: \'rdb\', dsProfile: \'dev\', teamName: teamName } }).then(function(response) { console.log(\'数据源返回数据\', response); field.options.loading = false; var { data } = response.data; if (data && data.length > 0) { var options_ = data.map(function(option) { option.value = option.dsName; return option; }); field.options.options = JSON.parse(JSON.stringify(options_)); self.setOptionsData(field, fieldName); } }).catch(function(err) { 