ropName\":\"xxxxxxxxxxxxxxxxxxxx\",\"propLabel\":\"true\",\"propDomain\":\"kpi\",\"cryptName\":\"xxxxx\",\"descr\":\"xxxxxxxxxxxxxxxxxxxx\",\"propId\":\"xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx\"}],\"fields\":[{\"name\":\"propName\",\"label\":\"prop_name\",\"width\":180},{\"name\":\"propLabel\",\"label\":\"prop_label\"},{\"name\":\"propDomain\",\"label\":\"prop_domain\"},{\"name\":\"cryptName\",\"label\":\"crypt_name\"},{\"name\":\"descr\",\"label\":\"descr\"},{\"name\":\"propId\",\"label\":\"prop_id\"}]}},{\"type\":\"elxFieldTable\",\"isGrid\":false,\"field\":\"outputField\",\"label\":\"读取字段\",\"remark\":\"如若表单数据隐藏，请放大表单！\",\"isRemark\":true,\"initialValue\":[],\"options\":{\"addOper\":true,\"editAllOper\":false,\"deleteOper\":true,\"rowKey\":\"index\",\"sortable\":false,\"index\":true,\"border\":false,\"importMetaModelOper\":true,\"importOper\":true,\"loading\":false,\"pagination\":true,\"model\":{\"fields\":[{\"name\":\"name\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"字段名\",\"type\":\"SelectInput\",\"editable\":true,\"options\":{\"options\":[],\"defaultSelect\":true,\"rules\":[{\"type\":\"required\",\"validator\":\"(value,cb, ref) => {if (!value) {return cb(\'必须填写字段名\');}else {return cb();}}\"}]}},{\"name\":\"label\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"字段中文名\",\"type\":\"input\",\"options\":{}},{\"name\":\"dataType\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"数据类型\",\"type\":\"select\",\"disabled\":true,\"options\":{\"options\":[{\"label\":\"INT\",\"value\":\"INT\"},{\"label\":\"BIGINT\",\"value\":\"BIGINT\"},{\"label\":\"DOUBLE\",\"value\":\"DOUBLE\"},{\"label\":\"DATE\",\"value\":\"DATE\"},{\"label\":\"STRING\",\"value\":\"STRING\"}]}}]}}}],\"layoutGrid\":true,\"parentStep\":\"datastash\",\"getDsName\":\"function(self,fields, fieldName, dsName, teamName) {console.log(\'数据源\', self, fields, fieldName, dsName, teamName);var fieldDatas=_.filter(fields, function(item) {return item.field == fieldName;});if (fieldDatas.length == 1) {var field=fieldDatas[0]; let workspaceName=self.props.apiInfo.workspaceName;axios.get(/_api/_/workspace/getDsListByName, {params: {dsType: \'clickhouse\',dsCategory: \'\',workspaceName: workspaceName}}).then(function(response) {console.log(\'数据源返回数据\', response);let {data}=response;if (data.data) {let options_=data.data.map(function(itm) {let obj={label: itm.label,value: itm.name,...itm,};return obj;});field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field,fieldName);};}).catch(function(err) {console.log(err);});};};\",\"getSchemas\":\"function(self,fieldName,dsName,query){if(!self){return;};let fields=self.props.fields.filter(function(item){return item.field==fieldName;});if(fields.length==1){var field=fields[0];const teamName=sessionStorage.getItem(\'teamName\');axios.get(/_api/_/modoAppTeamDs/ds/schema/${dsName}/${teamName}).then(function(response){console.log(\'modoAppTeamDs\',response);var {data} =response.data;const options=data.schemaList;if(options&&options.length>0){const schemaOptionObj={union:[],dev:[],prod:[]};options.map((option)=>{const schema=option.split(\'|\');if(schema.length>0){if(schema.length==1){schema.push(schema[0])};const devOption={label:schema[0],value:schema[0]};const prodOption={label:schema[1],value:schema[1]};let unionOption;if(schema[0]===schema[1]){unionOption={label:schema[0],value:schema[0]};}else{unionOption={label:开发：${schema[0]}生产：${schema[1]},value:${schema[0]}|${schema[1]}};}schemaOptionObj.union.push(unionOption);schemaOptionObj.dev.push(devOption);schemaOptionObj.prod.push(prodOption)}});field.options.options=JSON.parse(JSON.stringify(schemaOptionObj[\'union\']));self.setOptionsData(field,fieldName);}else{field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field,fieldName);};}).catch(function(err){});}}\",\"beforeRender\":\"function(self,fields, teamName) {const {currentCell,...formOptions}=self.props;formOptions.getDsName(self,fields,\'dsName\',\'\',teamName);const dsName=self.formRef.current.getFieldValue(\'dsName\');formOptions.getSchemas(self,\'dsSchema\',dsName);const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\').split(\'|\')[0];if(dsName){formOptions.getTabs(self,\'tabName\',dsName,schemaDev,\'\',\'edit\');}}\",\"getTabs\":\"function(self,fieldName, dsName,schema, query, type, selectInputData) { console.log(\'selectInputData\',self,fieldName, dsName, query, type, selectInputData);if (!self) {return;}let fields=self.props.fields.filter(function(item) {return item.field == fieldName;});if (fields.length == 1) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTables, {params:{pageNum: 1,pageSize: 20,dsName: dsName,schema: schema,tabName: query}}).then(function(response) {console.log(\'表名返回数据\', response);field.options.loading=false;var {data}=response.data;if (data && data.length > 0) {var options_=data.map(function(option) {let obj={label: option.table_name,value: option.table_name};return obj;});if (type == \'onSearch\') {selectInputData.setState({optionsNew: options_});}else {field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field, fieldName);};const tabName=self.formRef.current.getFieldValue(\'tabName\');if (type == \'edit\' && tabName) {console.log(\'selectInputData-edit\',); self.props.getOutputField(self, \'outputField\', dsName,schema, tabName, \'edit\');self.setOptionsData(field, fieldName);};} else {if(type==\'onSearch\'){console.log(\'selectInputData-onSearch\',);selectInputData.setState({optionsNew:[]});}else{field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field, fieldName);}}}).catch(function(err) {field.options.loading=false;});}}\",\"getOutputField\":\"(self,fieldName, dsName,schema, tabName, type) => {if (!self) {return};console.log(\'dsName,tabName\', dsName, tabName, self.props);let fields=self.props.fields.filter((item) => {return item.field == fieldName;});if (fields.length == 1 && tabName) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTableFields, {params:{dsName,tabName,schema,}}).then(function(response) {console.log(\'获取字段信息表名-的返回数据\', response);field.options.loading=false;var {data}=response.data;field.options.loading=false;if (data && data.length > 0) {console.log(\'outputFields\');let outputFields=_.map(data, function(item, index) {return {...item,\'label\': \'\',\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'name\': item.colname,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'};});let options_=_.map(data, function(item, index) {return {...item,\'label\': item.colname,\'value\': item.colname,\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'};});let TableFields=field.options.model.fields;let modelFields=TableFields.map(itm => {if (itm.name == \'name\') {let itm_={...itm,options: {...itm.options,options: options_}};return itm_;}else {return itm;}});field.options.model.fields=modelFields;self.setOptionsData(field, fieldName);if (type == \'add\') {self.formRef.current.setFieldsValue({outputField: outputFields});};}else{self.Message.error(${response.data.message});field.options.loading=false;self.setOptionsData(field, fieldName);};}).catch(function(err) {console.log(err);field.options.loading=false;self.setOptionsData(field, fieldName);});}}\",\"getPreviewData\":\"(setPreviewFun,setLoadingFun,setTableDataFun,self,fields,field)=> {if (!self) {return;};const dsName=self.formRef.current.getFieldValue(\'dsName\');const tabName=self.formRef.current.getFieldValue(\'tabName\');const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\').split(\'|\')[0];let params={dsName: dsName||\'\',table:tabName||\'\',fileType: \'clickhouse\',schema:schemaDev,dsConf:\'\',profile:\'dev\'};setLoadingFun(true);axios.post(/_api/_/data-integration/source/preview-data,params).then(function(response) {console.log(\'数据预览返回数据\',response);var{data}=response.data;setLoadingFun(false);if( response.data.success && data.success){let fields=[];let titles=data.titles||[];titles.forEach((item,index)=>{fields.push({name:item,label:item,});});setTableDataFun(data.datas|| [], fields);}else{setTableDataFun([], []);self.Message.warning(response.data.devMsg);};}).catch(err=>{setLoadingFun(false);console.log(err);});}\"}','icon-dmSource','clickhouse读','1','1','image','459968cba9494b7ab4d69ecd987d76f0',NULL,'seaTunnel');
