(self,\'tabName\',dsName,schemaDev,value,\'onSearch\',selectInputData);}\",\"onChange\":\"(self,value,item,option)=>{self.formRef.current.setFieldsValue({outputField:[]});const dsName=self.formRef.current.getFieldValue(\'dsName\');const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\').split(\'|\')[0];self.props.getOutputField(self,\'outputField\',dsName,schemaDev,value,\'add\');}\"}},{\"type\":\"select\",\"field\":\"mergeType\",\"label\":\"写入模式\",\"isRemark\":true,\"remark\":\"当数据已经存在时, 数据写入方案。APPEND:默认追加; DELETE:删与新数据Key相同的旧数据; MERGE: 结合条件，满足则删旧数据，否则追加。\",\"initialValue\":\"APPEND\",\"options\":{\"options\":[{\"label\":\"追加\",\"value\":\"APPEND\"},{\"label\":\"删除\",\"value\":\"DELETE\"},{\"label\":\"追加+删除\",\"value\":\"MERGE\"}]},\"relatedItems\":[\"deleteRule\"]},{\"type\":\"input\",\"field\":\"deleteRule\",\"label\":\"删除条件\",\"initialValue\":\"\",\"options\":{},\"isShow\":false,\"isRemark\":true,\"remark\":\"配置数据删除的条件，示例（数据有冲突时删除state字段值为0的行）： state =0 。对于新数据中满足 DELETE条件的记录，会删除表中对应主键的现有行且不插入该新数据;对于不满足 DELETE条件的记录，则按 APPEND 策略追加到表中；\",\"dependVal\":[\"MERGE\"]},{\"type\":\"select\",\"field\":\"retry\",\"label\":\"失败重试数\",\"isRemark\":true,\"remark\":\"写入数据是允许失败重试的次数，失败数超过配置的次数，任务会报错并停止执行.\",\"initialValue\":\"3\",\"options\":{\"options\":[{\"label\":\"1\",\"value\":\"1\"},{\"label\":\"3\",\"value\":\"3\"},{\"label\":\"5\",\"value\":\"5\"},{\"label\":\"10\",\"value\":\"10\"}]}},{\"type\":\"input\",\"field\":\"dorisBufferSize\",\"label\":\"buffer-size\",\"initialValue\":\"262144\",\"options\":{},\"isRemark\":true,\"remark\":\"用于缓存stream load数据的缓冲区大小.默认值为256*1024,单位为B,具体数据不用带单位.\"},{\"type\":\"input\",\"field\":\"dorisBatchSize\",\"label\":\"batch-size\",\"initialValue\":\"1024\",\"options\":{},\"isRemark\":true,\"remark\":\"每次http请求写入doris的批量大小,当row达到该大小或者执行checkpoint时,缓存的数据就会写入服务器.\"},{\"type\":\"elxFieldTable\",\"field\":\"outputField\",\"label\":\"写入字段\",\"remark\":\"配置字段写入规则！\",\"isRemark\":true,\"initialValue\":[],\"options\":{\"pagination\":true,\"addOper\":true,\"editAllOper\":false,\"deleteOper\":true,\"rowKey\":\"id\",\"sortable\":false,\"index\":true,\"border\":false,\"loading\":false,\"importMetaModelOper\":false,\"metaModelParam\":{\"getMetaTableNameDetail\":\"(props,teamName,metaTableName)=>{let resFields=[];let id=metaTableName?.id;const param={id,dataSrc:\'draft\',};axios.get(/api/get/logic/model/detail/from/dataps,{params:param}).then((response)=> {const{data}=response; if (data?.data) {let dataFields=data.data.fields;if(Array.isArray(dataFields)){data.data.fields.forEach(item => {resFields.push({...item,name:item.fieldName,label:item.fieldLabel,dataType:item.dataType,});});return resFields;};};}).catch(err=>{console.log(err);});return resFields;};\"},\"importOper\":true,\"value\":[],\"model\":{\"fields\":[{\"name\":\"name\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"写入字段名\",\"type\":\"SelectInput\",\"isFilter\":true,\"options\":{\"options\":[],\"defaultSelect\":true}},{\"name\":\"label\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"写入字段中文名\",\"type\":\"input\",\"options\":{}},{\"name\":\"dataType\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"写入数据类型\",\"type\":\"select\",\"options\":{\"showSearch\":true,\"options\":[]}},{\"name\":\"fieldMapping\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"来源字段\",\"type\":\"select\",\"options\":{\"options\":[]}}]}}}],\"layoutGrid\":true,\"parentStep\":\"datastash\",\"getDsName\":\"function(self,fields, fieldName, dsName, teamName) {console.log(\'数据源\', self, fields, fieldName, dsName, teamName);var fieldDatas=_.filter(fields, function(item) {return item.field == fieldName;});if (fieldDatas.length == 1) {var field=fieldDatas[0]; let workspaceName=self.props.apiInfo.workspaceName;axios.get(/_api/_/workspace/getDsListByName, {params: {dsType: \'doris\',dsCategory: \'\',workspaceName: workspaceName}}).then(function(response) {console.log(\'数据源返回数据\', response);let {data}=response;if (data.data) {let options_=data.data.map(function(itm) {let obj={label: itm.label,value: itm.name,...itm,};return obj;});field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field,fieldName);};}).catch(function(err) {console.log(err);});};};\",\"getFieldType\":\"function(self,fields, fieldName, dsType) {console.log(\'获取数据源字段类型\', self, fields, fieldName, dsType);var fieldDatas=_.filter(fields, function(item) {return item.field == fieldName});if (fieldDatas.length == 1) {var field=fieldDatas[0].options.model.fields[2];let workspaceName=self.props.apiInfo.workspaceName;const host=${window.location.host};const protocol=${window.location.protocol};const url_dataps=${protocol}//${host}/dataps;axios.get(${url_dataps}/api/get/model/physic/common/subjects, {params:{dsType: dsType}}).then(function(response) {console.log(\'字段类型返回\', response);let {data}=response;if (data.data) {let options_=data.data.dorisFieldDataType.map(function(itm) {let obj={label: itm.label,value: itm.name,...itm,};return obj});field.options.options=JSON.parse(JSON.stringify(options_))}}).catch(function(err) {console.log(err)})}};\",\"beforeRender\":\"function(self,fields, teamName) {const {currentCell,...formOptions}=self.props;formOptions.getDsName(self, fields, \'dsName\', \'\', teamName);formOptions.getFieldType(self, fields, \'outputField\', \'doris\');const dsName=self.formRef.current.getFieldValue(\'dsName\');formOptions.getSchemas(self,\'dsSchema\',dsName);const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\').split(\'|\')[0];if(dsName){formOptions.getTabs(self,\'tabName\',dsName,schemaDev,\'\',\'edit\');}}\",\"getTabs\":\"function(self,fieldName, dsName, schema, query, type, selectInputData) {if (!self) {return;}let fields=self.props.fields.filter(function(item) {return item.field == fieldName;});if (fields.length == 1) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTables, {params:{pageNum: 1,pageSize: 20,dsName: dsName,schema: schema,tabName: query}}).then(function(response) {console.log(\'表名返回数据\', response);field.options.loading=false;var {data}=response.data;if (data && data.length > 0) {var options_=data.map(function(option) {let obj={label: option.table_name,value: option.table_name};return obj;});if (type == \'onSearch\') {selectInputData.setState({optionsNew: options_});}else {field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field, fieldName);};const tabName=self.formRef.current.getFieldValue(\'tabName\');if (type == \'edit\' && tabName) {self.props.getOutputField(self, \'outputField\', dsName,schema, tabName, \'edit\');};} else {if (type == \'onSearch\') {selectInputData.setState({optionsNew: []});} else {field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field, fieldName);}}}).catch(function(err) {field.options.loading=false;});}}\",\"getOutputField\":\"(self,fieldName, dsName, schema, tabName, type) => {if (!self) {return};console.log(\'dsName,tabName\', dsName, tabName, self.props);let fields=self.props.fields.filter((item) => {return item.field == fieldName});if (fields.length == 1 && tabName) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTableFields, {params:{dsName,tabName,schema}}).then(function(response) {console.log(\'获取字段信息表名-的返回数据\', response);field.options.loading=false;var {data}=response.data;field.options.loading=false;console.log(\'test-field\', self.props.fields);if (data && data.length > 0) {let TableFields=field.options.model.fields;const fieldMappingMap=new Map();TableFields.filter(v => v.name == \'fieldMapping\')[0].options.options.forEach(v => fieldMappingMap.set(v.label.toUpperCase(), v.label));let outputFields=_.map(data, function(item, index) {let fieldMapping=fieldMappingMap.get(item.colname.toUpperCase());return {...item,\'label\': \'\',\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'name\': item.colname,\'fieldMapping\': fieldMapping,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'}});let options_=_.map(data, function(item, index) {return {...item,\'label\': item.colname,\'value\': item.colname,\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'}});let modelFields=TableFields.map(itm => {if (itm.name == \'name\') {let itm_={...itm,options: {...itm.options,options: options_}};return itm_}else {return itm}});field.options.model.fields=modelFields;self.setOptionsData(field, fieldName);if (type == \'add\') {self.formRef.current.setFieldsValue({outputField: outputFields})}} else {self.Message.error(${response.data.message});self.setOptionsData(field, fieldName);}}).catch(function(err) {console.log(err);field.options.loading=false;self.setOptionsData(field, fieldName);});}}\",\"getSql\":\"(setCodeFun,self,fields,field)=>{const from=self.formRef.current.getFieldsValue();let fieldList=from.outputField.map(item=>{let obj={name:item.name,label:item.label,type:item.dataType,};return obj;});let params={tabName:from.tabName||\'\',dsType:\'doris\',fieldList: fieldList||[]};console.log(\'params\',from,params);axios.post(/_api/_/dataaccess/tab/sql,params).then((response)=> {console.log(\'getSql\',response);let {data}=response;if(data.code == \'200\'){setCodeFun(data.message);};}).catch(err=>{console.log(err);});}\",\"getSchemas\":\"function(self,fieldName,dsName,query,){if(!self){return;};let fields=self.props.fields.filter(function(item){return item.field==fieldName;});if(fields.length==1){var field=fields[0];const teamName=sessionStorage.getItem(\'teamName\');axios.get(/_api/_/modoAppTeamDs/ds/schema/${dsName}/${teamName}).then(function(response){console.log(\'modoAppTeamDs\',response);var {data} =response.data;const options=data.schemaList;if(options&&options.length>0){const schemaOptionObj={union:[],dev:[],prod:[]};options.map((option)=>{const schema=option.split(\'|\');if(schema.length>0){if(schema.length==1){schema.push(schema[0])};const devOption={label:schema[0],value:schema[0]};const prodOption={label:schema[1],value:schema[1]};let unionOption;if(schema[0]===schema[1]){unionOption={label:schema[0],value:schema[0]};}else{unionOption={label:开发：${schema[0]}生产：${schema[1]},value:${schema[0]}|${schema[1]}};}schemaOptionObj.union.push(unionOption);schemaOptionObj.dev.push(devOption);schemaOptionObj.prod.push(prodOption)}});field.options.options=JSON.parse(JSON.stringify(schemaOptionObj[\'union\']));self.setOptionsData(field,fieldName);}else{field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field,fieldName);};}).catch(function(err){});}}\",\"executeSql\":\"(setMessage,dsProfile,runSql,self,fields,field)=>{const from=self.formRef.current.getFieldsValue();let dsProfile_=[\'dev\'];const dsSchema=self.formRef.current.getFieldValue(\'dsSchema\');if(dsProfile){dsProfile_=[\'dev\',\'pro\'];}else{dsProfile_=[\'dev\'];};let params={dsName:from.dsName||\'\',dsProfile:dsProfile_,dsType: \'doris\',windowId:\'windowId\',dsSchema:dsSchema,runSql:runSql||\'\'};axios.post(/_api/_/dataaccess/execute,params).then((response)=> {console.log(\'getSql\',response);let {data}=response;console.log(\'getSql--data\',data);if(data.success){setMessage({type:\'success\',msg:\'执行成功!\'});}else{setMessage({type:\'error\',msg:data.message});};}).catch(err=>{console.log(err);});}\"}','icon-dmSink','doris写','123','1','image','47def16b63844982ad33a778ead73fe7',NULL,'seaTunnel');
