};}).catch(function(err) {console.log(err);});};};\",\"beforeRender\":\"function(self,fields, teamName) {debugger;const {currentCell,...formOptions}=self.props;formOptions.getDsName(self,fields,\'dsName\',\'\',teamName);const dsName=self.formRef.current.getFieldValue(\'dsName\');if(dsName){formOptions.getTabs(self,\'tabName\',dsName,\'\',\'edit\');}}\",\"getTabs\":\"function(self,fieldName, dsName, query, type, selectInputData) { debugger;console.log(\'selectInputData\',self,fieldName, dsName, query, type, selectInputData);if (!self) {return;}let fields=self.props.fields.filter(function(item) {return item.field == fieldName;});if (fields.length == 1) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTables, {params:{pageNum: 1,pageSize: 20,dsName: dsName,tabName: query}}).then(function(response) {console.log(\'表名返回数据\', response);field.options.loading=false;var {data}=response.data;if (data && data.length > 0) {var options_=data.map(function(option) {let obj={label: option.table_name,value: option.table_name};return obj;});if (type == \'onSearch\') {selectInputData.setState({optionsNew: options_});}else {field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field, fieldName);};const tabName=self.formRef.current.getFieldValue(\'tabName\');if (type == \'edit\' && tabName) {console.log(\'selectInputData-edit\',); self.props.getOutputField(self, \'outputField\', dsName, tabName, \'edit\');self.setOptionsData(field, fieldName);};} else {if(type==\'onSearch\'){console.log(\'selectInputData-onSearch\',);selectInputData.setState({optionsNew:[]});}else{field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field, fieldName);}}}).catch(function(err) {field.options.loading=false;});}}\",\"getOutputField\":\"(self,fieldName, dsName, tabName, type) => {if (!self) {return};console.log(\'dsName,tabName\', dsName, tabName, self.props);let fields=self.props.fields.filter((item) => {return item.field == fieldName;});if (fields.length == 1 && tabName) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTableFields, {params:{dsName,tabName,}}).then(function(response) {console.log(\'获取字段信息表名-的返回数据\', response);field.options.loading=false;var {data}=response.data;field.options.loading=false;if (data && data.length > 0) {console.log(\'outputFields\');debugger;let outputFields=_.map(data, function(item, index) {return {...item,\'label\': \'\',\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'name\': item.colname,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'};});let options_=_.map(data, function(item, index) {return {...item,\'label\': item.colname,\'value\': item.colname,\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'};});let TableFields=field.options.model.fields;let modelFields=TableFields.map(itm => {if (itm.name == \'name\') {let itm_={...itm,options: {...itm.options,options: options_}};return itm_;}else {return itm;}});field.options.model.fields=modelFields;self.setOptionsData(field, fieldName);if (type == \'add\') {self.formRef.current.setFieldsValue({outputField: outputFields});};};}).catch(function(err) {console.log(err);field.options.loading=false;});}}\",\"getPreviewData\":\"(setPreviewFun,setLoadingFun,setTableDataFun,self,fields,field)=> {if (!self) {return;};const dsName=self.formRef.current.getFieldValue(\'dsName\');const tabName=self.formRef.current.getFieldValue(\'tabName\');let params={dsName: dsName||\'\',table:tabName||\'\',fileType: \'mysql\',dsConf:\'\',profile:\'dev\'};setLoadingFun(true);axios.post(/_api/_/data-integration/source/preview-data,params).then(function(response) {console.log(\'数据预览返回数据\',response);var{data}=response.data;setLoadingFun(false);if( response.data.success && data.success){let fields=[];let titles=data.titles||[];titles.forEach((item,index)=>{fields.push({name:item,label:item,});});setTableDataFun(data.datas|| [], fields);}else{setTableDataFun([], []);};}).catch(err=>{setLoadingFun(false);console.log(err);});}\"}','icon-dmSource','argodb读','1','1','image','4a27ac85222b4755b6bf3392c45755a8',NULL,'seaTunnel');
