insert into dataos_meta_proc_step_define (step_inst, children_type, domain, ext_conf, group_type, remark, step_cfg, step_icon, step_inst_label, step_seq, step_state, step_style, step_id, notify, run_engine) values('crtTmpTab','','develop','{\"allowCrtTab\":\"1\",\"regexp\":\"/n*/gi\",\"errorInfo\":\"\",\"notify\":\"\"}','TableOperation','“临时创建表”插件用于在指定数据库中创建数据库临时表\n数据库：创建临时表的目标数据库。\n模式名：表示要创建临时表的数据库schema归属\n表名：创建表的名称，可以不与原模型表明不一致\n创建语句：创建临时表的SQL语句，具体规则因各地需求不同，以当地实际情况为准\n','{\"fields\":[{\"type\":\"input\",\"field\":\"stepLabel\",\"label\":\"节点名\",\"options\":{\"placeholder\":\"请输入节点名称\"},\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"required\":true,\"rules\":\"[{ validator:function(value,cb,ref) {console.log(ref);if (!value) {return cb(\'必须填写节点名称\');}return cb();} }]\"},{\"type\":\"elxDs\",\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"options\":{\"metaTableNameVisible\":false,\"param\":{\"inline\":false,\"stepLabelShow\":false,\"scenario\":1,\"dsCategory\":\"rdb,mpp,bigdata,mostuse,storage,analytic\",\"storageType\":\"storage\",\"publicOptionName\":\"all\",\"env\":\"union\",\"parentDsNameShow\":false,\"labelShow\":true,\"labelSuffix\":\":\",\"labelWidth\":\"150px\",\"visible\":true},\"changeDsName\":\"function(that,config,val,currentValue,teamName,axios,base,optionItem){const {fields,...formOptions}=config; let fields_=fields.map(itm=>{if(itm.field==\'location\' && optionItem.dsType==\'hive\'){itm.isShow=true;return itm;}else if(itm.field == \'location\' && optionItem.dsType != \'hive\'){itm.isShow=false;return itm;}else{return itm;};});console.log(\'fields_\',fields_);formOptions.getDsName(that,fields,\'location\',val,teamName,base);console.log(\'val\',val,optionItem);}\"}},{\"type\":\"Editor\",\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"field\":\"sql\",\"label\":\"创建语句\",\"options\":{\"placeholder\":\"请输入sql\",\"language\":\"sql\"}}],\"parentStep\":\"\",\"getDsName\":\"(self,fields,fieldName,dsName,teamName,base)=>{var fieldDatas=_.filter(fields,function(item) {return item.field == fieldName;});if (fieldDatas.length == 1) {var field=fieldDatas[0];let axios=window.axios;let base=window.base;axios.get(/_api/_/modoAppDatasource/ds-location,{params:{dsName:dsName||\'\'}}).then((response)=> {if(response.data.success&&response.data.data){field.options.options=JSON.parse(JSON.stringify(response.data.data));self.setOptionsData(field,fieldName);};}).catch(err=>{console.log(err);});};}\",\"beforeRender\":\"(self,fields,teamName,base)=>{const {currentCell,...formOptions}=self.props;const dsName=self.formRef.current.getFieldValue(\'dsName\');formOptions.getDsName(self,fields,\'location\',dsName,teamName,axios,base);}\"}','icon-crtTmpTab','临时创建表','3','1','image','5',NULL,NULL);
