insert into dataos_meta_proc_step_define (step_inst, children_type, domain, ext_conf, group_type, remark, step_cfg, step_icon, step_inst_label, step_seq, step_state, step_style, step_id, notify, run_engine) values('s_kafkaWriter','','dataStream','{\"allowCrtTab\":\"1\",\"regexp\":\"/n*/gi\",\"errorInfo\":\"\",\"notify\":\"\"}','sink',NULL,'{\"fields\":[{\"type\":\"input\",\"field\":\"stepLabel\",\"label\":\"节点名\",\"options\":{\"placeholder\":\"请输入节点名称\"},\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"required\":true,\"rules\":\"[{ validator:function(value,cb,ref) {console.log(ref);if (!value) {return cb(\'必须填写节点名称\');}return cb();} }]\"},{\"label\":\"对象名称\",\"field\":\"tabIdLabel\",\"type\":\"input\",\"disabled\":true,\"hidden\":true,\"initialValue\":\"\",\"options\":{}},{\"label\":\"配置\",\"field\":\"formConfig\",\"type\":\"radioGroup\",\"options\":{\"options\":[{\"label\":\"基础\",\"value\":\"common\"},{\"label\":\"高级\",\"value\":\"advanced\"}],\"onChange\":\"function(self){}\"},\"initialValue\":\"common\",\"relatedItems\":[\"semantic\",\"acks\",\"transactionTimeoutMs\",\"batchSize\",\"lingerMs\",\"fetchTimeout\",\"bufferMemory\",\"requestTimeout\",\"poolSize\",\"customerConfig\"]},{\"label\":\"对象名称\",\"field\":\"tabId\",\"type\":\"SelectInput\",\"hidden\":false,\"required\":true,\"rules\":[{\"validator\":\"(value, cb, ref) => { if (!value) { return cb(\'请选择对象名称\'); } return cb(); }\"}],\"options\":{\"placeholder\":\"请输入表名\",\"options\":[],\"loading\":false,\"filterOption\":true,\"showSearch\":true,\"defaultSelect\":true,\"onSearch\":\"function(self, field, config, val, e) {console.log(\'-----onSearch\', self, field, config, val, e);self.props.getTabs(self,\'tabId\', \'\', val);}\",\"onChange\":\"(self,value,item,option)=>{console.log(\'-----change self,value,item,option\', self, value, item, option);const currentOptions = item.options.options;const selOption = currentOptions.filter((op) => { if (op.value === value) { return op } });self.formRef.current.setFieldsValue({ relFields: [], stepVars: [] });if (selOption.length > 0) { let n = selOption[0].fields; if (n) { n.forEach((fItem, index) => { fItem.index = index; fItem.name = fItem.fieldName; fItem.mappingType = \'associationField\'; fItem.label = fItem.fieldLabel; }); const nparse = self.props.matchField(self, n);self.formRef.current.setFieldsValue({ relFields: nparse, stepVars: nparse, tabIdLabel: selOption[0].label, tabName: selOption[0].name }); } else { self.props.getTabFields(self, value); } }else {self.props.getTabs(self,\'tabId\', \'\', \'\');}}\"}},{\"label\":\"生产者语义\",\"field\":\"semantic\",\"type\":\"radioGroup\",\"isRemark\":true,\"defaultValue\":\"atLeastOnce\",\"options\":{\"options\":[{\"label\":\"至少一次(at-least-once)\",\"value\":\"atLeastOnce\",\"remark\":\"数据不丢,但是可能重复,效率较高\"},{\"label\":\"精确一次(exactly-once)\",\"value\":\"exactlyOnce\",\"remark\":\"kafka0.11及其以上版本有效,kafka0.9和0.10只支持至少一次(at-least-once)语义;精确一次保证需要开启检查点,如果Flink程序异常到完成重启之间的时间大于Kafka的事务超时时间，则存在数据丢失的风险;精确一次会有一定的性能损耗,消费者需要设置isolation.level(设置为read_committed,默认是read_uncommitted)避免消费到脏数据;\"}]},\"dependVal\":[\"advanced\"]},{\"label\":\"事务超时时间(ms)\",\"field\":\"transactionTimeoutMs\",\"type\":\"InputNumber\",\"isRemark\":true,\"remark\":\"生产者语义设置为精确一次时该值有效，该值的设置需要大于检查点的间隔时间，小于kafka broker中transaction.max.timeout.ms(默认15分钟)配置;如果频繁出现事务超时,需要调整该参数,同时可能需要调整kafka broker参数;如果此值大于broker中的max.transaction.timeout.ms设置，则请求将失败，并报“InvalidTransactionTimeout”错误。\",\"options\":{},\"dependVal\":[\"advanced\"]},{\"label\":\"分区字段\",\"isRemark\":true,\"remark\":\"支持表达式配置或者前节点变量中的字段,计算出数据对应的kafka分区，相同的计算结果会写入到同一分区，如果同时指定partition(kafka模型),也会在指定分区中通过分区字段计算分区\",\"field\":\"partitionKey\",\"type\":\"input\",\"options\":{\"defaultValue\":\"\"}},{\"label\":\"acks\",\"field\":\"acks\",\"type\":\"select\",\"options\":{\"options\":[{\"label\":\"acks=0 无需等待leader的确认\",\"value\":\"0\"},{\"label\":\"acks=1 需要leader确认\",\"value\":\"1\"},{\"label\":\"acks=-1 所有的副本都完成后确认\",\"value\":\"-1\"}],\"defaultValue\":\"0\"},\"dependVal\":[\"advanced\"]},{\"label\":\"batch.size(Byte)\",\"field\":\"batchSize\",\"type\":\"inputNumber\",\"isRemark\":true,\"remark\":\"建议100000-200000(默认是16384),批处理大小(字节为单位),提高吞吐量时，可以提高该值\",\"options\":{\"defaultValue\":\"\"},\"dependVal\":[\"advanced\"]},{\"label\":\"linger.ms(Ms)\",\"field\":\"lingerMs\",\"type\":\"inputNumber\",\"isRemark\":true,\"remark\":\"建议10-100(默认是0)。为批处理的延迟提供了上限:一旦我们接受到记录超过了分区的 batch.size ，Producer 会忽略这个参数，立刻发送数据。但是如果累积的字节数少于 batch.size ，那么我们将在指定的时间内“逗留”(linger)，以等待更多的记录出现。\",\"options\":{\"defaultValue\":\"\"},\"dependVal\":[\"advanced\"]},{\"label\":\"buffer.memory(Byte)\",\"field\":\"bufferMemory\",\"type\":\"inputNumber\",\"isRemark\":true,\"remark\":\"生产者可以用来缓冲等待发送到服务器的记录的内存的总字节数，如果分区数很多或者超时异常较多则适当增加。默认32M。\",\"dependVal\":[\"advanced\"],\"options\":{\"defaultValue\":\"\"}},{\"label\":\"request.timeout.ms(Ms)\",\"field\":\"requestTimeout\",\"type\":\"inputNumber\",\"isShow\":true,\"isRemark\":true,\"remark\":\"配置控制客户端等待请求响应的最大时间量。如果在超时之前没有收到响应，客户端将在必要时重新发送请求，如果重试结束，则将失败请求。默认30秒。\",\"dependVal\":[\"advanced\"],\"options\":{\"defaultValue\":\"\"}},{\"label\":\"poolSize\",\"field\":\"poolSize\",\"type\":\"inputNumber\",\"isRemark\":true,\"remark\":\"配置kafka生产者的线程数，默认为5\",\"dependVal\":[\"advanced\"],\"options\":{\"defaultValue\":\"5\"}},{\"label\":\"其他参数设置(json)\",\"isRemark\":true,\"field\":\"customerConfig\",\"type\":\"textArea\",\"remark\":\"kafka生产者其他参数设置，json格式。如果存在和上面重复的配置，则优先使用上面的配置\",\"dependVal\":[\"advanced\"],\"options\":{\"defaultValue\":\"\"}},{\"type\":\"elxFieldTable\",\"isGrid\":false,\"field\":\"relFields\",\"label\":\"columns\",\"initialValue\":[],\"options\":{\"addOper\":true,\"editAllOper\":false,\"deleteOper\":true,\"rowKey\":\"index\",\"sortable\":false,\"index\":true,\"border\":false,\"loading\":false,\"pagination\":true,\"model\":{\"fields\":[{\"name\":\"label\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"字段中文名\",\"type\":\"input\",\"options\":{}},{\"name\":\"id\",\"valueType\":\"string\",\"defaultValue\"