insert into dataos_meta_proc_step_define (step_inst, children_type, domain, ext_conf, group_type, remark, step_cfg, step_icon, step_inst_label, step_seq, step_state, step_style, step_id, notify, run_engine) values('if',NULL,'develop','{\"allowCrtTab\":\"1\",\"regexp\":\"/n*/gi\",\"errorInfo\":\"\",\"notify\":\"\"}','ArryVarIf','“变量比较”插件用于处理程序逻辑判断，实现程序不同路径选择。对程序条件进行判断后选择执行不同的程序分支。\r\n在使用变量比较插件的时候，需要预先定义程序的分支条数，然后连接“变量比较”插件和相关分支插件才能双击进行条件编辑，不能直接拖动“变量比较”插件，而不设置需要连接的下一步程序分支，否则插件不能进行编辑操作。\r\n注意：“变量比较”插件之后不能再接“变量比较”插件，需要添加中途节点插件。\r\n关系运算符：\r\n等于符号:==，不等于符号:!= ，大于符号:>， 小于符号:<，大于等于符号:>= ，小于等于符号:<= 。\r\n逻辑运算符：\r\n与（&&）、非（!）、或（||）','{\"fields\":[{\"type\":\"input\",\"field\":\"stepLabel\",\"label\":\"节点名\",\"options\":{\"placeholder\":\"请输入节点名称\"},\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"required\":true,\"rules\":\"[{ validator:function(value,cb,ref) {console.log(ref);if (!value) {return cb(\'必须填写节点名称\');}return cb();} }]\",\"initialValue\":\"\"},{\"type\":\"TableForm\",\"labelCol\":{\"span\":8},\"wrapperCol\":{\"span\":16},\"field\":\"statements\",\"label\":\"条件组合\",\"remark\":\"如若表单数据隐藏，请放大表单！\",\"isRemark\":true,\"initialValue\":[{\"stepId\":\"测试\",\"stepLabel\":\"测试\",\"expression\":\"测试\"}],\"options\":{\"pagination\":false,\"rowKey\":\"id\",\"sortable\":false,\"oper\":false,\"editAllOper\":true,\"className\":\"fsdafsdfds\",\"model\":{\"fields\":[{\"name\":\"stepId\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"步骤id\",\"type\":\"input\",\"options\":{\"disabled\":true}},{\"name\":\"stepLabel\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"步骤名\",\"type\":\"input\",\"options\":{\"disabled\":true}},{\"name\":\"expression\",\"valueType\":\"string\",\"defaultValue\":\"\",\"label\":\"条件\",\"type\":\"input\",\"options\":{}}]}}}]}','icon-if','变量比较','110','1','image','89',NULL,NULL);
