tion;if(schema[0]===schema[1]){unionOption={label:schema[0],value:schema[0]};}else{unionOption={label:开发：${schema[0]}生产：${schema[1]},value:${schema[0]}|${schema[1]}};}schemaOptionObj.union.push(unionOption);schemaOptionObj.dev.push(devOption);schemaOptionObj.prod.push(prodOption)}});field.options.options=JSON.parse(JSON.stringify(schemaOptionObj[\'union\']));self.setOptionsData(field,fieldName);}else{field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field,fieldName);};}).catch(function(err){});}}\",\"beforeRender\":\"function(self,fields, teamName) {const {currentCell,...formOptions}=self.props;formOptions.getDsName(self, fields, \'dsName\', \'\', teamName);const dsName=self.formRef.current.getFieldValue(\'dsName\');formOptions.getSchemas(self, \'dsSchema\', dsName);const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\');if (dsName&&schemaDev) {formOptions.getTabs(self, \'tabName\', dsName, schemaDev.split(\'|\')[0], \'\', \'edit\'); }}\",\"getTabs\":\"function(self,fieldName, dsName,schema, query, type, selectInputData) { console.log(\'selectInputData\',self,fieldName, dsName, query, type, selectInputData);if (!self) {return;}let fields=self.props.fields.filter(function(item) {return item.field == fieldName;});if (fields.length == 1) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTables, {params:{pageNum: 1,pageSize: 20,dsName: dsName,schema: schema,tabName: query}}).then(function(response) {console.log(\'表名返回数据\', response);field.options.loading=false;var {data}=response.data;if (data && data.length > 0) {var options_=data.map(function(option) {let obj={label: option.table_name,value: option.table_name};return obj;});if (type == \'onSearch\') {selectInputData.setState({optionsNew: options_});}else {field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field, fieldName);};const tabName=self.formRef.current.getFieldValue(\'tabName\');if (type == \'edit\' && tabName) {console.log(\'selectInputData-edit\',); };} else {if(type==\'onSearch\'){console.log(\'selectInputData-onSearch\',);selectInputData.setState({optionsNew:[]});}else{field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field, fieldName);}}}).catch(function(err) {field.options.loading=false;});}}\",\"getPreviewData\":\"(setPreviewFun,setLoadingFun,setTableDataFun,self,fields,field)=> {if (!self) {return;};const dsName=self.formRef.current.getFieldValue(\'dsName\');const tabName=self.formRef.current.getFieldValue(\'tabName\');const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\').split(\'|\')[0]; if(!tabName){ setLoadingFun(false); return self.Message.warning(\'请先填写表名！\'); }; let params={dsName: dsName||\'\',table:tabName||\'\',fileType: \'oracle-mdbs\',schema:schemaDev,dsConf:\'\',profile:\'dev\'};setLoadingFun(true);axios.post(/_api/_/data-integration/source/preview-data,params).then(function(response) {console.log(\'数据预览返回数据\',response);var{data}=response.data;setLoadingFun(false);if( response.data.success && data.success){let fields=[];let titles=data.titles||[];titles.forEach((item,index)=>{fields.push({name:item,label:item,});});setTableDataFun(data.datas|| [], fields);}else{setTableDataFun([], []);self.Message.warning(response.data.devMsg);};}).catch(err=>{setLoadingFun(false);console.log(err);});}\",\"dsKey\":\"dsName\",\"tabKey\":\"tabName\",\"getFields\":\"function(ref,values,callback,tabData,canChangeRela){axios.get(\'/_api/_/modoAppTabInfos/getTableFields\',{params:{dsName:values.dsName,tabName:values.tabName, schema: values.dsSchema}}).then(function(res){if(res.data&&Array.isArray(res.data.data)){callback(res.data.data.map(function(row){return{name:row.colname,dataType:row.sourceDataType}}));const pathInitialValue=ref.current.props.fields.find(function(item){return item.field===\'path\'})?.initialValue||\'\';const path=pathInitialValue+tabData.name+\'_sql2hdfs\';ref.current.setFieldValue(\'path\',path);return}throw\'err\'}).catch(fu