ype);var fieldDatas=_.filter(fields, function(item) {return item.field == fieldName});if (fieldDatas.length == 1) {var field=fieldDatas[0].options.model.fields[2];let workspaceName=self.props.apiInfo.workspaceName;const host=${window.location.host};const protocol=${window.location.protocol};const url_dataps=${protocol}//${host}/dataps;axios.get(${url_dataps}/api/get/model/physic/common/subjects, {params:{dsType: dsType}}).then(function(response) {console.log(\'字段类型返回\', response);let {data}=response;if (data.data) {let options_=data.data.kingbasees8FieldDataType.map(function(itm) {let obj={label: itm.label,value: itm.name,...itm,};return obj});field.options.options=JSON.parse(JSON.stringify(options_))}}).catch(function(err) {console.log(err)})}};\",\"beforeRender\":\"function(self,fields, teamName) {const {currentCell,...formOptions}=self.props;formOptions.getDsName(self, fields, \'dsName\', \'\', teamName);formOptions.getFieldType(self, fields, \'outputField\', \'kingbasees8\');const dsName=self.formRef.current.getFieldValue(\'dsName\');formOptions.getSchemas(self,\'dsSchema\',dsName);const schemaDev=self.formRef.current.getFieldValue(\'dsSchema\').split(\'|\')[0];if(dsName){formOptions.getTabs(self,\'tabName\',dsName,schemaDev,\'\',\'edit\');}}\",\"getTabs\":\"function(self,fieldName, dsName, schema, query, type, selectInputData) {if (!self) {return;}let fields=self.props.fields.filter(function(item) {return item.field == fieldName;});if (fields.length == 1) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTables, {params:{pageNum: 1,pageSize: 20,dsName: dsName,schema: schema,tabName: query}}).then(function(response) {console.log(\'表名返回数据\', response);field.options.loading=false;var {data}=response.data;if (data && data.length > 0) {var options_=data.map(function(option) {let obj={label: option.table_name,value: option.table_name};return obj;});if (type == \'onSearch\') {selectInputData.setState({optionsNew: options_});}else {field.options.options=JSON.parse(JSON.stringify(options_));self.setOptionsData(field, fieldName);};const tabName=self.formRef.current.getFieldValue(\'tabName\');if (type == \'edit\' && tabName) {self.props.getOutputField(self, \'outputField\', dsName,schema, tabName, \'edit\');};} else {if (type == \'onSearch\') {selectInputData.setState({optionsNew: []});} else {field.options.options=JSON.parse(JSON.stringify([]));self.setOptionsData(field, fieldName);}}}).catch(function(err) {field.options.loading=false;});}}\",\"getOutputField\":\"(self,fieldName, dsName, schema, tabName, type) => {if (!self) {return};console.log(\'dsName,tabName\', dsName, tabName, self.props);let fields=self.props.fields.filter((item) => {return item.field == fieldName});if (fields.length == 1 && tabName) {var field=fields[0];field.options.loading=true;axios.get(/_api/_/modoAppTabInfos/getTableFields, {params:{dsName,tabName,schema}}).then(function(response) {console.log(\'获取字段信息表名-的返回数据\', response);field.options.loading=false;var {data}=response.data;field.options.loading=false;console.log(\'test-field\', self.props.fields);if (data && data.length > 0) {let TableFields=field.options.model.fields;const fieldMappingMap=new Map();TableFields.filter(v => v.name == \'fieldMapping\')[0].options.options.forEach(v => fieldMappingMap.set(v.label.toUpperCase(), v.label));let outputFields=_.map(data, function(item, index) {let fieldMapping=fieldMappingMap.get(item.colname.toUpperCase());return {...item,\'label\': \'\',\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'name\': item.colname,\'fieldMapping\': fieldMapping,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'}});let options_=_.map(data, function(item, index) {return {...item,\'label\': item.colname,\'value\': item.colname,\'id\': item.value,\'index\': index + 1,\'index_\': item.index,\'dataType\': item.sourceDataType ? item.sourceDataType : \'varchar\'}});let modelFields=TableFields.map(itm => {if (itm.name == \'name\') {let itm_={...itm,options: {...itm.options,options: options_}};return itm_}else {return itm}});field.options.model.fields=modelFields;self.setOptionsData(field, fieldName);if (type == \'add\') {self.formRef.current.setFieldsValue({outputField: outputFields})}} else {self.Message.error(${response.data.message});self.setOptionsData(field, fieldName);}}).catch(function(err) {console.log(err);field.options.loading=false;self.setOptionsData(field, fieldName);});}}\",\"getSql\":\"(setCodeFun,self,fields,field)=>{const from=self.formRef.current.getFieldsValue();let fieldList=from.outputField.map(item=>{let obj={name:item.name,label:item.label,type:item.dataType,};return obj;});let params={tabName:from.tabName||\'\',dsType:\'kingbasees8\',fieldList: fieldList||[]};console.log(\'params\',from,params);axios.post(/_api/_/dataaccess/tab/sql,params).then((response)=> {console.log(\'getSql\',response);let {data}=response;if(data.code == \'200\'){setCodeFun(data.message);};}).catch(err=>{console.log(err);});}\",\"getSchemas\":\"function(self,fieldName,dsName,query,){if(!self){return;};let fields=self.props.fields.filter(function(item){return item.field==fieldName;});if(fields.length==1){var field=fields[0];const teamName=sessionStorage.getItem(\'teamName\');axios.get(/_api/_/modoAppTeamDs/ds/schema/${dsName}/${teamName}).then(function(response){console.log(\'modoAppTeamDs\',response);var {data} =response.data;const options=data.schemaList;if(options&&options.length>0){const schemaOptionObj={union:[],dev:[],prod:[]};options.map((option)=>{const schema=option.split(\'|\');if(schema.length>0){if(schema.length==1){schema.push(schema[0])};const devOption={label:schema[0],value:schema[0]};const prodOption={label:schema[1],value:schema[1]};let unionOption;if(schema[0]===schema[1]){unionOption={label:schema[0],value:schema[0]};}else{unionOption={label:开发：${schema[0]}生产：${schema[1]},value:${schema[0]}|${schema[1]}};}schemaOptionObj.union.push(unionOption);schemaOptionObj.dev.push(d