/* 2026-01-16 hulin 提示词功能相关字段更新 */
-- 本体提示词表
CREATE TABLE if not exists ontology_prompt
(
    id             VARCHAR(32)   NOT NULL COMMENt '主键ID',
    prompt_name    VARCHAR(100)  NULL COMMENT '提示词名称',
    prompt_desc    VARCHAR(1000) NULL COMMENT '提示词说明',
    prompt_content LONGTEXT      NULL COMMENT '提示词内容',
    prompt_type    INT           NULL COMMENT '提示词类型: 1-OAG提示词, 0-普通提示词',
    default_type   INT           NULL COMMENT '默认提示词: 1-默认, 0-自定义',
    ontology_id    VARCHAR(100)  NULL COMMENT '本体id',
    owner_id       VARCHAR(100)  NULL COMMENt '创建用户',
    workspace_id   VARCHAR(100)  NULL COMMENt '工作空间',
    create_time    DATETIME      NULL COMMENT '创建时间',
    last_update    DATETIME      NULL COMMENT '更新时间',
    sync_status    INT           NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
    oper_status    INT           NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
    PRIMARY KEY (id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci  COMMENT='提示词管理表';

ALTER TABLE ontology_prompt CHANGE owner_id owner_id VARCHAR(100) NULL COMMENT '创建用户';
ALTER TABLE ontology_prompt CHANGE workspace_id workspace_id VARCHAR(100) NULL COMMENT '工作空间';

CREATE TABLE if not exists ontology_manage (
  id varchar(32) COLLATE utf8mb4_general_ci NOT NULL COMMENT '本体管理器唯一id',
  create_time datetime DEFAULT NULL COMMENT '创建时间',
  last_update datetime DEFAULT NULL COMMENT '修改时间',
  oper_status int DEFAULT NULL COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
  sync_status int DEFAULT NULL COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
  is_favorite int DEFAULT NULL COMMENT '状态，1为收藏，0为不收藏',
  latest_version varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '最新版本号',
  ontology_desc text COLLATE utf8mb4_general_ci COMMENT '本体管理器描述',
  ontology_label varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体管理器中文名',
  ontology_name varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本体管理器英文名',
  owner_id varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拥有者标识',
  publish_time datetime DEFAULT NULL COMMENT '发布时间',
  publish_user varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '发布人',
  status int DEFAULT NULL COMMENT '状态，1为启用，0为禁用',
  sync_label int DEFAULT NULL COMMENT '同步标记',
  workspace_id varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '工作空间/团队名',
  is_recommend int DEFAULT NULL COMMENT '推荐标识，1为推荐，0为不推荐',
  PRIMARY KEY (id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- 默认提示词
DELETE FROM ontology_prompt WHERE default_type  = '1' AND prompt_type = 0;

INSERT INTO ontology_prompt(id, prompt_name, prompt_desc, prompt_content, prompt_type, default_type, ontology_id, owner_id, workspace_id, create_time, last_update, sync_status, oper_status)
SELECT REPLACE(UUID(), '-', ''), t1.ontology_label, '由系统自动生成的默认提示词，适用于本体中不限定具体场景的通用性问答', NULL, 0, 1, t1.id, owner_id, NULL, NOW(), NOW(), 1, 0 FROM ontology_manage t1 WHERE t1.oper_status < 3 AND NOT EXISTS (SELECT 1 FROM ontology_prompt t2 WHERE t2.ontology_id = t1.id AND t2.default_type = '1' AND t2.prompt_type = 0);

DELETE FROM ontology_prompt WHERE default_type  = '1' AND prompt_type = 1;

INSERT INTO ontology_prompt(id, prompt_name, prompt_desc, prompt_content, prompt_type, default_type, ontology_id, owner_id, workspace_id, create_time, last_update, sync_status, oper_status)
SELECT REPLACE(UUID(), '-', ''), t1.ontology_label, '由系统自动生成的默认提示词，适用于本体中不限定具体场景的通用性问答', NULL, 1, 1, t1.id, owner_id, NULL, NOW(), NOW(), 1, 0 FROM ontology_manage t1 WHERE t1.oper_status < 3 AND NOT EXISTS (SELECT 1 FROM ontology_prompt t2 WHERE t2.ontology_id = t1.id AND t2.default_type = '1' AND t2.prompt_type = 1);

-- 本体导入/导出异步任务表
CREATE TABLE `ontology_action_process`
(
    `id`          VARCHAR(32)   NOT NULL COMMENT '动作处理唯一id',
    `task_id`     VARCHAR(64)   NULL     COMMENT '任务ID',
    `task_name`   VARCHAR(100)  NULL     COMMENT '动作NAME',
    `task_type`   VARCHAR(20)   NULL     COMMENT '程序类型',
    `ontology_id` VARCHAR(100)  NULL     COMMENT '本体ID',
    `file_name`   VARCHAR(200)  NULL     COMMENT '文件名',
    `api_param`   VARCHAR(4000) NULL     COMMENT '执行参数',
    `api_path`    VARCHAR(1000) NULL     COMMENT '执行地址',
    `message`     LONGTEXT      NULL     COMMENT '执行消息',
    `state`       INT           NULL     COMMENT '执行状态',
    `create_user` VARCHAR(100)  NULL     COMMENT '创建用户',
    `start_time`  DATETIME      NULL     COMMENT '开始时间',
    `end_time`    DATETIME      NULL     COMMENT '结束时间',
    `create_time` DATETIME      NULL     COMMENT '创建时间',
    `last_update` DATETIME      NULL     COMMENT '修改时间',
    `sync_status` INT           NULL     COMMENT '待同步状态，1为新建，2为修改，3为删除，0为已同步',
    `oper_status` INT           NULL     COMMENT '操作状态：0 - 新建，1 - 修改，2 - 同步，3 - 删除',
    PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='本体动作处理表';

-- 本体导入/导出任务详情表
CREATE TABLE if not exists  `ontology_action_process_detail`
(
    `id`            VARCHAR(100) NOT NULL COMMENT '主键ID',
    `ontology_id`   VARCHAR(100) NULL     COMMENT '本体ID',
    `task_id`       VARCHAR(100) NULL     COMMENT '任务ID',
    `parent_id`     VARCHAR(100) NULL     COMMENT '关联资源ID',
    `resource_type` VARCHAR(100) NULL     COMMENT '资源类型: object - 对象；attr - 属性；link - 关系；logic - 逻辑；action - 动作；interface - 接口',
    `content`       LONGTEXT     NULL     COMMENT '资源内容',
    `state`         INT          NULL     COMMENT '状态: 0 - 已存在; 1 - 新增; 2 - 覆盖',
    PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='本体导入/导出任务详情表';

